<span class="line"><span class="line"><span style="color:#D4D4D4;">    </span><span style="color:#DCDCAA;">Subscribe</span><span style="color:#D4D4D4;">&lt;</span><span style="color:#4EC9B0;">MechanicalBlockAttachedEvent</span><span style="color:#D4D4D4;">&gt;();</span></span></span>
